// ===================================================
// WF-09 Step 1: POST 본문 파싱 + 입력값 검증 + 텍스트 sanitize
// 필수 필드: member_id, review_id, answer
// 보안: HTML 태그 제거, XSS 방지, 제어 문자 제거
// ===================================================

const input = $input.first().json;
const body = input.body || input;

// === 텍스트 정제 (제어 문자 제거 + 길이 제한) ===
function sanitizeText(str, maxLen) {
  if (!str) return '';
  maxLen = maxLen || 500;
  return String(str)
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
    .trim()
    .substring(0, maxLen);
}

// === HTML/XSS 위험 요소 제거 ===
// <script>, <iframe>, javascript:, on이벤트 속성 등 제거
function sanitizeAnswer(str) {
  if (!str) return '';
  return String(str)
    // HTML 태그 전체 제거
    .replace(/<[^>]*>/gi, '')
    // javascript: 프로토콜 제거
    .replace(/javascript\s*:/gi, '')
    // data: 프로토콜 제거
    .replace(/data\s*:/gi, '')
    // vbscript: 프로토콜 제거
    .replace(/vbscript\s*:/gi, '')
    // on이벤트 핸들러 패턴 제거 (onclick, onerror 등)
    .replace(/on\w+\s*=\s*["'][^"']*["']/gi, '')
    .replace(/on\w+\s*=\s*\S+/gi, '')
    // 제어 문자 제거
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
    .trim();
}

// === HTML XSS 방지 (이메일용) ===
function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// === 필수 필드 추출 ===
const memberId = sanitizeText(body.member_id, 100);
const reviewId = sanitizeText(body.review_id, 100);
const answerRaw = body.answer || '';

// === 필수 필드 검증 ===
const missingFields = [];
if (!memberId) missingFields.push('member_id');
if (!reviewId) missingFields.push('review_id');
if (!String(answerRaw).trim()) missingFields.push('answer');

if (missingFields.length > 0) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'MISSING_PARAMS',
          message: missingFields.join(', ') + ' 파라미터가 필요합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === 답변 텍스트 정제 (HTML 태그 + XSS 제거 + 1000자 제한) ===
const sanitizedAnswer = sanitizeAnswer(answerRaw).substring(0, 1000);

if (!sanitizedAnswer) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'MISSING_PARAMS',
          message: '유효한 답변 내용이 필요합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _valid: true,
    memberId,
    reviewId,
    answer: sanitizedAnswer,
    _safe: {
      answer: escapeHtml(sanitizedAnswer)
    }
  }
}];

// ===================================================
// WF-09 Step 2: 파트너 인증 확인
// ===================================================

const response = $input.first().json;
const partnerList = response.list || [];
const validData = $('Validate Input').first().json;

if (partnerList.length === 0) {
  return [{
    json: {
      _partnerFound: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'NOT_PARTNER',
          message: '파트너로 등록되지 않은 회원입니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const partner = partnerList[0];

if (partner.status !== 'active') {
  return [{
    json: {
      _partnerFound: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'PARTNER_INACTIVE',
          message: '비활성 상태의 파트너 계정입니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _partnerFound: true,
    _partner: {
      partner_code: partner.partner_code || '',
      partner_name: partner.partner_name || '',
      member_id: partner.member_id || ''
    },
    _input: validData
  }
}];

// ===================================================
// WF-09 Step 3: 후기 존재 확인 + class_id 추출
// 후기가 없으면 REVIEW_NOT_FOUND 에러
// ===================================================

const response = $input.first().json;
const reviewList = response.list || [];
const prevData = $('Check Partner Auth').first().json;

if (reviewList.length === 0) {
  return [{
    json: {
      _reviewFound: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'REVIEW_NOT_FOUND',
          message: '해당 후기를 찾을 수 없습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const review = reviewList[0];

// class_id 추출 (Links 필드 또는 문자열)
let classId = '';
if (Array.isArray(review.class_id) && review.class_id.length > 0) {
  classId = review.class_id[0].class_id || review.class_id[0].Title || '';
} else if (typeof review.class_id === 'string') {
  classId = review.class_id;
}

// partner_code 추출 (후기에 직접 있는 경우)
let reviewPartnerCode = '';
if (Array.isArray(review.partner_code) && review.partner_code.length > 0) {
  reviewPartnerCode = review.partner_code[0].partner_code || review.partner_code[0].Title || '';
} else if (typeof review.partner_code === 'string') {
  reviewPartnerCode = review.partner_code;
}

return [{
  json: {
    _reviewFound: true,
    _review: {
      Id: review.Id || review.id,
      review_id: review.review_id || '',
      class_id: classId,
      partner_code: reviewPartnerCode,
      reviewer_name: review.reviewer_name || '',
      rating: review.rating || 0,
      content: review.content || ''
    },
    _partner: prevData._partner,
    _input: prevData._input
  }
}];

// ===================================================
// WF-09 Step 4: 소유권 2단계 검증
// 1차: 후기에 partner_code 직접 있으면 비교
// 2차: class_id -> tbl_Classes 조회 -> partner_code 비교
// ===================================================

const classResponse = $input.first().json;
const classList = classResponse.list || [];
const prevData = $('Check Review Exists').first().json;
const review = prevData._review;
const partner = prevData._partner;
const inputData = prevData._input;

// 1차: 후기에 partner_code가 있으면 직접 비교
if (review.partner_code) {
  if (review.partner_code !== partner.partner_code) {
    return [{
      json: {
        _owned: false,
        _errorResponse: {
          success: false,
          error: {
            code: 'REVIEW_NOT_OWNED',
            message: '본인 소유의 클래스 후기만 답변할 수 있습니다.'
          },
          timestamp: new Date().toISOString()
        }
      }
    }];
  }
  // 1차 검증 통과
  return [{
    json: {
      _owned: true,
      _review: review,
      _partner: partner,
      _input: inputData
    }
  }];
}

// 2차: class_id로 클래스 조회하여 partner_code 비교
if (classList.length === 0) {
  return [{
    json: {
      _owned: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'REVIEW_NOT_OWNED',
          message: '후기의 클래스 정보를 확인할 수 없습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const classRecord = classList[0];

// partner_code 추출 (Links 필드 또는 문자열)
let classPartnerCode = '';
if (Array.isArray(classRecord.partner_code) && classRecord.partner_code.length > 0) {
  classPartnerCode = classRecord.partner_code[0].partner_code || classRecord.partner_code[0].Title || '';
} else if (typeof classRecord.partner_code === 'string') {
  classPartnerCode = classRecord.partner_code;
}

if (classPartnerCode !== partner.partner_code) {
  return [{
    json: {
      _owned: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'REVIEW_NOT_OWNED',
          message: '본인 소유의 클래스 후기만 답변할 수 있습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _owned: true,
    _review: review,
    _partner: partner,
    _input: inputData
  }
}];

// ===================================================
// WF-09 Step 5: 성공 응답 구성
// ===================================================

const ownershipData = $('Check Review Ownership').first().json;
const review = ownershipData._review;
const inputData = ownershipData._input;

return [{
  json: {
    success: true,
    data: {
      review_id: review.review_id,
      class_id: review.class_id,
      answer: inputData.answer,
      answer_at: new Date().toISOString(),
      message: '후기 답변이 저장되었습니다.'
    },
    timestamp: new Date().toISOString()
  }
}];
